text:
What is the output of the following code?
```javascript
const arr = [1, 2, 15];
arr.sort();
console.log(arr);
```

What is the output?
```javascript
var a = 1;
function b() {
  a = 10;
  return;
  function a() {}
}
b();
console.log(a);
```

What is the output of this loop?
```javascript
for (var i = 0; i < 3; i++) {
  setTimeout(() => console.log(i), 1);
}
```

What happens when this code executes?
```javascript
let x = 10;
(function() {
  console.log(x);
  let x = 20;
})();
```

What is the output?
```javascript
const obj = {
  name: 'Alice',
  greet: function() {
    return () => console.log(this.name);
  }
};
const fn = obj.greet();
fn();
```

What does this code log?
```javascript
const user = {
  name: 'Bob',
  printName() { console.log(this.name); }
};
setTimeout(user.printName, 100);
```

What is the output of chained `.bind()` calls?
```javascript
function f() { return this.a; }
const bound = f.bind({a: 1}).bind({a: 2});
console.log(bound());
```

What is logged?
```javascript
const x = { foo: 1 }, y = { foo: 2 }, obj = {};
obj[x] = 'X';
obj[y] = 'Y';
console.log(obj[x]);
```

What does the `delete` operator actually do in this scenario?
```javascript
const arr = [1, 2, 3];
delete arr[1];
console.log(arr.length);
```

What happens when a constructor function explicitly returns an object?
```javascript
function Person() { 
  this.age = 20; 
  return { age: 30 }; 
}
const p = new Person();
console.log(p.age);
```

Determine the exact output order:
```javascript
setTimeout(() => console.log('A'), 0);
Promise.resolve().then(() => console.log('B'));
console.log('C');
```

What happens if you `await` a non-Promise value?
```javascript
async function foo() {
  const res = await 5;
  console.log(res);
}
foo();
```

What is the output?
```javascript
const arr = [1, 2, 3];
arr.forEach(async (num) => {
  await new Promise(r => setTimeout(r, 10)); 
  console.log(num);
});
console.log('Done');
```

What is the output?
```javascript
const obj = { a: { b: 1 } };
const { a: { b } } = obj;
console.log(a);
```

What does this output?
```javascript
function outer() {
  const inner = () => console.log(arguments[0]);
  inner(2);
}
outer(1);
```

What is logged?
```javascript
function* gen() { 
  yield 1; 
  yield 2; 
}
const g = gen();
console.log(g.next().value);
```

What does `strings[0]` equal in this tagged template?
```javascript
function tag(strings, ...values) {
  console.log(strings[0]);
}
tag`Hello ${'World'}!`;
```

What is the output?
```javascript
try {
  throw new Error();
} catch (e) {
  var x = 1;
  let y = 2;
}
console.log(x);
```

Is this valid code?
```javascript
const arr = [{a: 1}];
arr[0].a = 2;
```

What is the output?
```javascript
const arr = [1, , 3];
console.log(arr.map(x => x * 2));
```
